class TrustManager:
    """Manages user trust scores to weight contributions."""

    @staticmethod
    def get_trust_score(user_id: str) -> float:
        return user_trust_scores.get(user_id, 0.5)  # Default trust

    @staticmethod
    def update_trust_score(user_id: str, contribution_quality: float):
        current = user_trust_scores.get(user_id, 0.5)
        # Exponential moving average
        alpha = 0.1
        user_trust_scores[user_id] = current * (1 - alpha) + contribution_quality * alpha

    @staticmethod
    def is_trusted(user_id: str) -> bool:
        score = TrustManager.get_trust_score(user_id)
        contributions = len(user_contributions.get(user_id, []))
        return score >= CONTRIBUTION_TRUST_THRESHOLD and contributions >= MIN_CONTRIBUTIONS_FOR_TRUST

    @staticmethod
    def check_rate_limit(user_id: str) -> bool:
        today = datetime.utcnow().date()
        contributions_today = sum(
            1 for c in user_contributions.get(user_id, [])
            if c['timestamp'].date() == today
        )
        return contributions_today < MAX_SAMPLES_PER_USER_PER_DAY


