def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


def require_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        user_id = request.headers.get('X-User-ID')
        api_key = request.headers.get('X-API-Key')
        if not user_id or not api_key:
            return jsonify({"error": "Authentication required"}), 401
        # In production, validate api_key against stored credentials
        request.user_id = user_id
        return f(*args, **kwargs)
    return decorated


def require_admin(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        user_id = request.headers.get('X-User-ID')
        if user_id not in admin_users:
            return jsonify({"error": "Admin access required"}), 403
        return f(*args, **kwargs)
    return decorated


def build_model(num_classes: int) -> tf.keras.Model:
    """Build image classification model."""
    model = tf.keras.Sequential([
        tf.keras.layers.Input(shape=(IMAGE_SIZE[0], IMAGE_SIZE[1], NUM_CHANNELS)),
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu', padding='same'),
        tf.keras.layers.BatchNormalization(),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu', padding='same'),
        tf.keras.layers.BatchNormalization(),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(128, (3, 3), activation='relu', padding='same'),
        tf.keras.layers.BatchNormalization(),
        tf.keras.layers.GlobalAveragePooling2D(),
        tf.keras.layers.Dense(256, activation='relu'),
        tf.keras.layers.Dropout(0.5),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])

    model.compile(
        optimizer='adam',
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )
    return model


def load_and_preprocess_csv(filepath: str) -> tuple:
    """Load CSV and preprocess for training."""
    df = pd.read_csv(filepath)

    # Validate structure
    valid, errors = data_validator.validate_csv_structure(df)
    if not valid:
        raise ValueError(f"Invalid CSV structure: {errors}")

    # Validate labels
    valid, errors = data_validator.validate_labels(df['label'])
    if not valid:
        raise ValueError(f"Invalid labels: {errors}")

    # Validate pixel values
    valid, errors = data_validator.validate_pixel_values(df)
    if not valid:
        raise ValueError(f"Invalid pixel values: {errors}")

    pixel_cols = [c for c in df.columns if c.startswith('pixel_')]
    images = df[pixel_cols].values.astype(np.float32) / PIXEL_MAX
    images = images.reshape(-1, IMAGE_SIZE[0], IMAGE_SIZE[1], NUM_CHANNELS)
    labels = df['label'].values.astype(np.int32)

    return images, labels, df


