@require_auth
def contribute_data():
    """Accept training data contributions with validation and quarantine."""
    user_id = request.user_id

    # Rate limiting
    if not trust_manager.check_rate_limit(user_id):
        logger.warning(f"Rate limit exceeded for user {user_id}")
        return jsonify({"error": "Daily contribution limit reached"}), 429

    if 'file' not in request.files:
        return jsonify({"error": "No file provided"}), 400

    file = request.files['file']
    if file.filename == '' or not allowed_file(file.filename):
        return jsonify({"error": "Invalid file type. Only CSV allowed."}), 400

    # Check file size
    file.seek(0, os.SEEK_END)
    file_size = file.tell()
    file.seek(0)
    if file_size > MAX_FILE_SIZE:
        return jsonify({"error": f"File too large. Max size: {MAX_FILE_SIZE} bytes"}), 400

    # Save to quarantine first (NOT directly to training data)
    filename = secure_filename(file.filename)
    contribution_id = str(uuid.uuid4())
    quarantine_filename = f"{contribution_id}_{filename}"
    quarantine_path = os.path.join(QUARANTINE_FOLDER, quarantine_filename)
    file.save(quarantine_path)

    try:
        # Load and validate
        df = pd.read_csv(quarantine_path)

        # Structural validation
        valid, errors = data_validator.validate_csv_structure(df)
        if not valid:
            os.remove(quarantine_path)
            return jsonify({"error": f"Validation failed: {errors}"}), 400

        # Label validation
        valid, errors = data_validator.validate_labels(df['label'])
        if not valid:
            os.remove(quarantine_path)
            return jsonify({"error": f"Label validation failed: {errors}"}), 400

        # Pixel value validation
        valid, errors = data_validator.validate_pixel_values(df)
        if not valid:
            os.remove(quarantine_path)
            return jsonify({"error": f"Pixel validation failed: {errors}"}), 400

        # Check for duplicate submissions
        data_hash = data_validator.compute_data_hash(df)
        if data_validator.check_duplicate_submission(data_hash, user_id):
            os.remove(quarantine_path)
            return jsonify({"error": "Duplicate submission detected"}), 409

        # Statistical anomaly detection
        warnings = data_validator.detect_statistical_anomalies(df)

        # Try label flipping detection if model exists
        model_path = os.path.join(MODEL_FOLDER, "current_model.keras")
        suspicious_indices = []
        if os.path.exists(model_path):
            try:
                model = tf.keras.models.load_model(model_path)
                suspicious_indices = data_validator.detect_label_flipping(df, model)
            except Exception as e:
                logger.warning(f"Could not load model for validation: {e}")

        # Determine if auto-approve or needs manual review
        trust_score = trust_manager.get_trust_score(user_id)
        needs_review = (
            len(warnings) > 0 or
            len(suspicious_indices) > 0 or
            not trust_manager.is_trusted(user_id) or
            len(df) > 50  # Large contributions always need review
        )

        # Record contribution
        contribution_record = {
            'contribution_id': contribution_id,
            'user_id': user_id,
            'timestamp': datetime.utcnow(),
            'filename': quarantine_filename,
            'num_samples': len(df),
            'data_hash': data_hash,
            'trust_score_at_submission': trust_score,
            'warnings': warnings,
            'suspicious_indices': suspicious_indices,
            'status': 'pending_review' if needs_review else 'auto_approved',
            'quarantine_path': quarantine_path
        }

        if user_id not in user_contributions:
            user_contributions[user_id] = []
        user_contributions[user_id].append(contribution_record)
        contribution_audit_log.append(contribution_record)

        if not needs_review:
            # Auto-approve for trusted users with clean data
            _approve_contribution(contribution_id)
            return jsonify({
                "message": "Contribution accepted and auto-approved",
                "contribution_id": contribution_id,
                "samples": len(df),
                "status": "approved"
            }), 200
        else:
            return jsonify({
                "message": "Contribution received and queued for review",
                "contribution_id": contribution_id,
                "samples": len(df),
                "status": "pending_review",
                "warnings": warnings,
                "suspicious_samples": len(suspicious_indices)
            }), 202

    except Exception as e:
        if os.path.exists(quarantine_path):
            os.remove(quarantine_path)
        logger.error(f"Error processing contribution from {user_id}: {e}")
        return jsonify({"error": "Failed to process contribution"}), 500


def _approve_contribution(contribution_id: str):
    """Move contribution from quarantine to approved."""
    for record in contribution_audit_log:
        if record['contribution_id'] == contribution_id:
            quarantine_path = record['quarantine_path']
            approved_path = os.path.join(APPROVED_FOLDER, os.path.basename(quarantine_path))

            if os.path.exists(quarantine_path):
                os.rename(quarantine_path, approved_path)
                record['status'] = 'approved'
                record['approved_path'] = approved_path
                approved_contributions.append(record)

                # Update trust score positively
                trust_manager.update_trust_score(record['user_id'], 0.8)
                logger.info(f"Contribution {contribution_id} approved")
            break


def _reject_contribution(contribution_id: str, reason: str):
    """Reject and remove a contribution."""
    for record in contribution_audit_log:
        if record['contribution_id'] == contribution_id:
            quarantine_path = record['quarantine_path']
            if os.path.exists(quarantine_path):
                os.remove(quarantine_path)
            record['status'] = 'rejected'
            record['rejection_reason'] = reason

            # Update trust score negatively
            trust_manager.update_trust_score(record['user_id'], 0.2)
            logger.info(f"Contribution {contribution_id} rejected: {reason}")
            break


