@require_auth
@require_admin
def train_model():
    """Train model using only approved contributions with trust-weighted sampling."""
    if not approved_contributions:
        return jsonify({"error": "No approved training data available"}), 400

    try:
        all_images = []
        all_labels = []
        all_weights = []

        for record in approved_contributions:
            approved_path = record.get('approved_path')
            if not approved_path or not os.path.exists(approved_path):
                continue

            try:
                images, labels, df = load_and_preprocess_csv(approved_path)
                trust_score = trust_manager.get_trust_score(record['user_id'])

                # Weight samples by contributor trust score
                weights = np.full(len(labels), trust_score)

                all_images.append(images)
                all_labels.append(labels)
                all_weights.append(weights)
            except Exception as e:
                logger.warning(f"Skipping contribution {record['contribution_id']}: {e}")
                continue

        if not all_images:
            return jsonify({"error": "No valid training data after filtering"}), 400

        X = np.concatenate(all_images, axis=0)
        y = np.concatenate(all_labels, axis=0)
        sample_weights = np.concatenate(all_weights, axis=0)

        num_classes = len(np.unique(y))
        if num_classes < 2:
            return jsonify({"error": "Need at least 2 classes for training"}), 400

        # Shuffle data
        indices = np.random.permutation(len(X))
        X = X[indices]
        y = y[indices]
        sample_weights = sample_weights[indices]

        # Split into train and validation
        split_idx = int(0.8 * len(X))
        X_train, X_val = X[:split_idx], X[split_idx:]
        y_train, y_val = y[:split_idx], y[split_idx:]
        weights_train = sample_weights[:split_idx]

        model = build_model(num_classes)

        # Train with sample weights (trust-weighted)
        history = model.fit(
            X_train, y_train,
            sample_weight=weights_train,
            validation_data=(X_val, y_val),
            epochs=10,
            batch_size=32,
            verbose=1
        )

        # Evaluate
        val_loss, val_accuracy = model.evaluate(X_val, y_val, verbose=0)

        # Only save if validation accuracy is reasonable
        model_path = os.path.join(MODEL_FOLDER, "current_model.keras")
        if os.path.exists(model_path):
            old_model = tf.keras.models.load_model(model_path)
            old_loss, old_accuracy = old_model.evaluate(X_val, y_val, verbose=0)
            # Only update if new model is not significantly worse
            if val_accuracy < old_accuracy - 0.05:
                logger.warning(
                    f"New model accuracy ({val_accuracy:.4f}) significantly worse than "
                    f"old ({old_accuracy:.4f}). Possible poisoning. Not saving."
                )
                return jsonify({
                    "warning": "Model degradation detected. Training result not saved.",
                    "new_accuracy": float(val_accuracy),
                    "old_accuracy": float(old_accuracy)
                }), 200

        # Save with versioning
        timestamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
        versioned_path = os.path.join(MODEL_FOLDER, f"model_{timestamp}.keras")
        model.save(versioned_path)
        model.save(model_path)

        logger.info(f"Model trained. Val accuracy: {val_accuracy:.4f}")

        return jsonify({
            "message": "Model trained successfully",
            "validation_accuracy": float(val_accuracy),
            "validation_loss": float(val_loss),
            "training_samples": len(X_train),
            "validation_samples": len(X_val),
            "num_classes": num_classes,
            "model_version": timestamp
        }), 200

    except Exception as e:
        logger.error(f"Training failed: {e}")
        return jsonify({"error": f"Training failed: {str(e)}"}), 500


@app.route('/api/predict', methods=['POST'])
@require_auth
def predict():
    """Make predictions using the current model."""
    model_path = os.path.join(MODEL_FOLDER, "current_model.keras")
    if not os.path.exists(model_path):
        return jsonify({"error": "No trained model available"}), 404

    if 'file' not in request.files:
        return jsonify({"error": "No file provided"}), 400

    file = request.files['file']
    if not allowed_file(file.filename):
        return jsonify({"error": "Invalid file type"}), 400

    try:
        temp_path = os.path.join(UPLOAD_FOLDER, secure_filename(f"pred_{uuid.uuid4()}.csv"))
        file.save(temp_path)

        images, _, _ = load_and_preprocess_csv(temp_path)
        model = tf.keras.models.load_model(model_path)
        predictions = model.predict(images, verbose=0)

        results = []
        for i, pred in enumerate(predictions):
            results.append({
                "sample_index": i,
                "predicted_class": int(np.argmax(pred)),
                "confidence": float(np.max(pred)),
                "probabilities": pred.tolist()
            })

        os.remove(temp_path)
        return jsonify({"predictions": results}), 200

    except Exception as e:
        if os.path.exists(temp_path):
            os.remove(temp_path)
        return jsonify({"error": str(e)}), 500


